/**
 * @file 266B.CPP
 * @brief Simulates the rearrangement of a queue of boys ('B') and girls ('G').
 *
 * This program models a discrete-time process where adjacent boys and girls
 * in a line swap positions. A boy ('B') will swap with a girl ('G') to his
 * right in a single time step.
 *
 * @b Algorithm:
 * The simulation proceeds for a fixed number of time steps (t). In each step,
 * a new state of the queue is generated by iterating through the current
 * state and performing all possible adjacent 'B'/'G' swaps. This approach uses
 * a temporary string to store the state for the next time step, ensuring that
 * all swaps within a single time step are based on the state at the beginning
 * of that step.
 *
 * @b Complexity:
 * - Time: O(n * t), where n is the number of people in the queue and t is the
 *   number of time steps. The nested loops dominate the runtime.
 * - Space: O(n) to store the queue string and its temporary copy.
 */
#include <bits/stdc++.h>
using namespace std;

int main() {
  // n: number of people, t: time steps
  int n, t;
  cin >> n >> t;
  string inp;
  cin >> inp;

  /**
   * @brief Main simulation loop.
   *
   * Iterates for 't' time steps to simulate the queue's evolution.
   */
  for (int i = 0; i < t; i++) {
    string temp = inp; // Temporary string to hold the state for the next time step.
    /**
     * @brief Inner loop to find and perform swaps.
     *
     * Iterates through the queue to find adjacent pairs of 'B' and 'G'
     * that need to be swapped.
     */
    for (int j = 0; j < n - 1; j++) {
      /**
       * @brief Swap condition.
       *
       * If a boy ('B') is immediately followed by a girl ('G'),
       * their positions are swapped in the temporary state.
       */
      if (inp[j] == 'B' && inp[j + 1] == 'G') {
        temp[j] = 'G';
        temp[j + 1] = 'B';
      }
    }
    inp = temp; // Update the queue state for the next time step.
  }

  // Output the final state of the queue after 't' seconds.
  cout << inp;
}
